#include <stdio.h>
#include <stdlib.h>

// Define the structure for a tree node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new node
Node* newNode(int key) {
    Node* node = (Node*) malloc(sizeof(Node));
    node->val = key;
    node->left = node->right = NULL;
    return node;
}

// Function to get the height of a tree
int getHeight(Node* root) {
    if (root == NULL)
        return 0;

    int leftHeight = getHeight(root->left);
    if (leftHeight == -1)
        return -1;

    int rightHeight = getHeight(root->right);
    if (rightHeight == -1)
        return -1;

    if (abs(leftHeight - rightHeight) > 1)
        return -1;

    return 1 + (leftHeight > rightHeight ? leftHeight : rightHeight);
}

// Function to check if a tree is height-balanced
int isHeightBalanced(Node* root) {
    return getHeight(root) != -1;
}

int main() {
    int T;
    scanf("%d", &T);

    for (int t = 0; t < T; t++) {
        int N;
        scanf("%d", &N);

        Node* nodes[N];
        for (int i = 0; i < N; i++) {
            nodes[i] = newNode(i + 1);
        }

        for (int i = 0; i < N - 1; i++) {
            int pi, ci;
            char Ri;
            scanf("%d %d %c", &pi, &ci, &Ri);
            pi--; ci--;
            if (Ri == 'L') {
                nodes[pi]->left = nodes[ci];
            } else {
                nodes[pi]->right = nodes[ci];
            }
        }

        if (isHeightBalanced(nodes[0])) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }

    return 0;
}

