import java.util.Scanner;

// Define the class for a tree node
class Node {
    int val;
    Node left;
    Node right;

    public Node(int key) {
        val = key;
        left = right = null;
    }
}

public class Main {
    // Function to get the height of a tree
    public static int getHeight(Node root) {
        if (root == null)
            return 0;

        int leftHeight = getHeight(root.left);
        if (leftHeight == -1)
            return -1;

        int rightHeight = getHeight(root.right);
        if (rightHeight == -1)
            return -1;

        if (Math.abs(leftHeight - rightHeight) > 1)
            return -1;

        return 1 + Math.max(leftHeight, rightHeight);
    }

    // Function to check if a tree is height-balanced
    public static boolean isHeightBalanced(Node root) {
        return getHeight(root) != -1;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();

        for (int t = 0; t < T; t++) {
            int N = scanner.nextInt();

            Node[] nodes = new Node[N];
            for (int i = 0; i < N; i++) {
                nodes[i] = new Node(i + 1);
            }

            for (int i = 0; i < N - 1; i++) {
                int pi = scanner.nextInt() - 1;
                int ci = scanner.nextInt() - 1;
                char Ri = scanner.next().charAt(0);
                if (Ri == 'L') {
                    nodes[pi].left = nodes[ci];
                } else {
                    nodes[pi].right = nodes[ci];
                }
            }

            if (isHeightBalanced(nodes[0])) {
                System.out.println("YES");
            } else {
                System.out.println("NO");
            }
        }
    }
}

